#include <hip/hip_runtime.h>
#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <algorithm>
#include <vector>

// --- Kernel: pure read-only streaming with reduction ---
__global__ void read_only_streaming(const float* __restrict__ src,
                                     unsigned int* __restrict__ sink,
                                     size_t num_elements,
                                     unsigned int block_id_global)
{
    // Use vectorized float4 loads for coalesced memory access
    size_t idx = (size_t)blockIdx.x * blockDim.x * 4 + threadIdx.x * 4;
    float4 accum = make_float4(0.f, 0.f, 0.f, 0.f);

    // Stride over the buffer; each block processes a chunk
    size_t stride = (size_t)blockDim.x * blockDim.x * 4;
    for (size_t i = idx; i < num_elements; i += stride) {
        // Vectorized float4 load — this is the read traffic
        float4 v = reinterpret_cast<const float4*>(src)[i / 4];
        // Accumulate so the compiler cannot optimize away the reads
        accum.x += v.x + v.y + v.z + v.w;
        accum.y += v.x * v.y;
        accum.z += v.z * v.w;
        accum.w += (v.x + 1.0f) * (v.w + 2.0f);
    }

    // Reduce across threads in the block
    __shared__ float4 sdata[256]; // up to 256 threads
    sdata[threadIdx.x] = accum;
    __syncthreads();

    // Block-level reduction (simple, sufficient for correctness)
    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (threadIdx.x < s) {
            sdata[threadIdx.x].x += sdata[threadIdx.x + s].x;
            sdata[threadIdx.x].y += sdata[threadIdx.x + s].y;
            sdata[threadIdx.x].z += sdata[threadIdx.x + s].z;
            sdata[threadIdx.x].w += sdata[threadIdx.x + s].w;
        }
        __syncthreads();
    }

    // Write a single scalar from the block result to a sink buffer
    // (effectively never taken, but prevents dead-code elimination)
    // Use a large threshold so the branch is never taken in practice
    if (block_id_global == 0 && accum.x > 1e20f) {
        sink[blockIdx.x] = 1;
    }
}

// --- Second kernel variant with 256 threads, float8 for more bandwidth ---
// Actually, float4 is already good. Let's use more blocks instead.

int main(int argc, char** argv)
{
    // GPU setup
    hipDeviceProp_t prop;
    hipGetDeviceProperties(&prop, 0);
    printf("GPU: %s, Global Mem: %.1f GB, Max threads/block: %d, Max blocks: %d\n",
           prop.name, prop.totalGlobalMem / 1e9, prop.maxThreadsPerBlock,
           prop.maxGridSize[0]);

    // --- Buffer sizing ---
    // Use a 4 GiB buffer to ensure we go through HBM, far exceeding cache
    size_t buffer_bytes = 4ULL * 1024ULL * 1024ULL * 1024ULL; // 4 GiB
    size_t num_elements = buffer_bytes / sizeof(float);

    printf("Buffer size: %zu bytes (%.1f GiB), elements: %zu\n",
           buffer_bytes, (double)buffer_bytes / (1024.0*1024.0*1024.0),
           num_elements);

    // Allocate with HIP (pinned memory is better for bandwidth)
    float* d_src = nullptr;
    unsigned int* d_sink = nullptr;

    // Allocate on device directly
    hipMalloc(&d_src, buffer_bytes);
    if (!d_src) {
        // Try smaller buffer
        buffer_bytes = 2ULL * 1024ULL * 1024ULL * 1024ULL;
        num_elements = buffer_bytes / sizeof(float);
        printf("Falling back to 2 GiB buffer\n");
        hipMalloc(&d_src, buffer_bytes);
    }

    // Small sink buffer for DCE prevention
    hipMalloc(&d_sink, 4096 * sizeof(unsigned int));

    if (!d_src) {
        fprintf(stderr, "HIP malloc failed\n");
        return 1;
    }

    // Initialize buffer with values so we read real data
    // Use hipFill to quickly populate (doesn't count as timed bandwidth)
    float init_val = 1.0f;
    hipMemset(d_src, 0, buffer_bytes);
    hipMemset(d_sink, 0, 4096 * sizeof(unsigned int));

    // Fill with 1.0f (each byte is 0x00 — but we want variation)
    // Actually let's fill with a pattern so data is interesting
    float* h_src = (float*)malloc(buffer_bytes);
    for (size_t i = 0; i < num_elements; i += 4) {
        h_src[i]   = (float)(i + 1);
        h_src[i+1] = (float)(i + 2) * 0.5f;
        h_src[i+2] = (float)(i + 3) * 0.25f;
        h_src[i+3] = (float)(i + 4) * 0.125f;
    }

    hipMemcpyAsync(d_src, h_src, buffer_bytes, hipMemcpyHostToDevice);
    hipDeviceSynchronize();
    free(h_src);

    // --- Kernel configuration ---
    // 256 threads/block, float4 loads → each thread reads 16 bytes
    // We want many blocks to saturate HBM
    int threads_per_block = 256;
    int blocks_per_grid = min(prop.maxGridSize[0], 16384);
    printf("Using %d blocks, %d threads/block\n", blocks_per_grid, threads_per_block);

    // --- Warmup ---
    printf("Warmup...\n");
    hipEvent_t warmup_start, warmup_stop;
    hipEventCreate(&warmup_start);
    hipEventCreate(&warmup_stop);
    hipEventRecord(warmup_start);
    read_only_streaming<<<blocks_per_grid, threads_per_block>>>(d_src, d_sink, num_elements, 0);
    hipEventRecord(warmup_stop);
    hipEventSynchronize(warmup_stop);
    hipEventDestroy(warmup_start);
    hipEventDestroy(warmup_stop);

    // --- Timing: multiple iterations ---
    int num_iters = 20;
    std::vector<double> times_ms;
    times_ms.reserve(num_iters);

    printf("Timing %d iterations...\n", num_iters);

    hipEvent_t start, stop;
    hipEventCreate(&start);
    hipEventCreate(&stop);

    for (int iter = 0; iter < num_iters; iter++) {
        // Clear sink between iterations to ensure writes happen
        hipMemsetAsync(d_sink, 0, 4096 * sizeof(unsigned int));

        hipEventRecord(start);
        read_only_streaming<<<blocks_per_grid, threads_per_block>>>(d_src, d_sink, num_elements, 0);
        hipEventRecord(stop);
    }

    hipEventSynchronize(stop);

    float t_ms;
    hipEventElapsedTime(&t_ms, start, stop);
    double total_ms = t_ms;
    double per_iter_ms = total_ms / num_iters;

    // We can't easily get per-iteration times from this, so compute from total
    // Actually let's do per-iteration timing for proper median

    hipEventDestroy(start);
    hipEventDestroy(stop);

    // Re-do with per-iteration timing for proper median
    start = nullptr;
    stop = nullptr;
    hipEventCreate(&start);
    hipEventCreate(&stop);

    times_ms.clear();
    for (int iter = 0; iter < num_iters; iter++) {
        hipMemsetAsync(d_sink, 0, 4096 * sizeof(unsigned int));
        hipEventRecord(start);
        read_only_streaming<<<blocks_per_grid, threads_per_block>>>(d_src, d_sink, num_elements, 0);
        hipEventRecord(stop);
        hipEventSynchronize(stop);

        float elapsed;
        hipEventElapsedTime(&elapsed, start, stop);
        times_ms.push_back(elapsed);
    }

    hipEventDestroy(start);
    hipEventDestroy(stop);

    // Compute median
    std::sort(times_ms.begin(), times_ms.end());
    double median_ms = times_ms[num_iters / 2];
    if (num_iters % 2 == 0) {
        median_ms = (times_ms[num_iters/2 - 1] + times_ms[num_iters/2]) / 2.0;
    }

    // Compute bandwidth: buffer_bytes / median_time
    // This is read-only bandwidth since the kernel only reads from d_src
    double bandwidth_GBps = buffer_bytes / (median_ms * 1e6) * 1e9 / 1e9;
    // buffer_bytes in bytes, median_ms in ms
    // bytes / ms = GB/s * 1e6
    // bandwidth = buffer_bytes / (median_ms * 1e-3) = buffer_bytes / median_ms * 1e3  bytes/s
    // in GB/s: buffer_bytes / median_ms * 1e3 / 1e9 = buffer_bytes / median_ms / 1e6
    bandwidth_GBps = (double)buffer_bytes / median_ms / 1e6;

    printf("\n=== Results ===\n");
    printf("Median kernel time: %.3f ms\n", median_ms);
    printf("Buffer bytes: %zu\n", buffer_bytes);
    printf("Computed HBM read bandwidth: %.2f GB/s\n", bandwidth_GBps);

    // Print individual times for debugging
    printf("All times (ms): ");
    for (auto t : times_ms) printf("%.3f ", t);
    printf("\n");

    // Output in the required format
    printf("HBM_BANDWIDTH_GBPS=%.2f\n", bandwidth_GBps);
    printf("buffer_bytes=%zu\n", buffer_bytes);

    // Cleanup
    hipFree(d_src);
    hipFree(d_sink);

    return 0;
}

