// Pure read-only streaming kernel.
// Each thread reads float4 vectors across the entire buffer.
// Accumulator is written to global memory (one per block) to prevent DCE.
__global__ void read_bandwidth_kernel(const float* __restrict__ src,
                                       size_t num_elements,
                                       volatile size_t* __restrict__ sink)
{
    size_t idx    = (size_t)blockIdx.x * (size_t)blockDim.x * 4u + (size_t)threadIdx.x * 4u;
    size_t stride = (size_t)gridDim.x * (size_t)blockDim.x * 4u;

    size_t acc = 0;

    for (size_t i = idx; i < num_elements; i += stride) {
        float4 v = reinterpret_cast<const float4*>(src)[i / 4u];
        acc += (size_t)(v.x + v.y + v.z + v.w);
    }

    // Write result per-block to a volatile sink to prevent DCE
    sink[blockIdx.x] = acc;
}

