           prop.multiProcessorCount, prop.maxThreadsPerBlock,
           prop.maxGridSize[0]);

    // --- Buffer sizing ---
    // 4 GiB to ensure we go through HBM (far exceeding cache)
    size_t buffer_bytes = 4ULL * 1024ULL * 1024ULL * 1024ULL;
