    // Fill buffer with interesting data on host, then copy to device
    size_t host_alloc_size = buffer_bytes;
    float* h_src = (float*)malloc(host_alloc_size);
    if (!h_src) {
        buffer_bytes = 2ULL * 1024ULL * 1024ULL * 1024ULL;
        num_elements = buffer_bytes / sizeof(float);
