// Use a block reduction so the read data is actually consumed.
// Each block reduces its chunk into a single double, then writes to sink.
__global__ void read_bandwidth_kernel(const float* __restrict__ src,
                                       double* __restrict__ sink,
                                       size_t num_elements,
                                       size_t chunk_size)   // elements per block (must be multiple of 4)
{
    // Shared memory for block reduction
    extern __shared__ double sdata[];

    // Local accumulation
    size_t base = (size_t)blockIdx.x * chunk_size;
    size_t tidx = (size_t)threadIdx.x;
    double local_acc = 0.0;

    // Each thread reads float4 vectors across its chunk
    for (size_t i = tidx; i < chunk_size; i += (size_t)blockDim.x) {
        size_t global_idx = base + i;
        float4 v = reinterpret_cast<const float4*>(src)[global_idx / 4u];
        local_acc += (double)v.x + (double)v.y + (double)v.z + (double)v.w;
    }

    // Block reduction via shared memory
    sdata[tidx] = local_acc;
    __syncthreads();

    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (tidx < s) {
            sdata[tidx] += sdata[tidx + s];
        }
        __syncthreads();
    }

    // Thread 0 writes the block result
    if (tidx == 0) {
        sink[blockIdx.x] = sdata[0];
    }
}

